def find_two_non_repeating_elements(yaz):
    xor_sum = 0
    for num in yaz:
        xor_sum ^= num

    # Find the rightmost set bit
    # This bit will be different between the two non-repeating numbers
    rightmost_set_bit = xor_sum & (-xor_sum)

    num1 = 0
    num2 = 0

    for num in yaz:
        if (num & rightmost_set_bit) != 0:
            num1 ^= num
        else:
            num2 ^= num

    return num1, num2
